{
  "resolution_strategies": [
    {
      "resolution_strategy_id": "RS1_insert_consent_before_personal_data",
      "change_operations": [
        {
          "operation": "insert_before",
          "parameters": {
            "target_activity_label": "Request personal data",
            "new_activity_label": "obtain data processing consent"
          }
        },
        {
          "operation": "modify_resource",
          "parameters": {
            "target_activity_label": "obtain data processing consent",
            "new_resource": "data controller"
          }
        }
      ],
      "evaluation": {
        "compliance_degree": {
          "value": "full",
          "reason": "The missing activity is added directly before 'Request personal data', satisfying the required precedence relation. Assigning it to 'data controller' also satisfies the executed_by condition."
        },
        "resolution_context_consistency": {
          "value": "high",
          "reason": "No additional resolution context requirements are provided, and the strategy preserves the existing process behavior while adding only the required consent step."
        },
        "change_cost": {
          "value": "low",
          "reason": "Only one activity is inserted and one resource assignment is modified. The change is small and localized."
        },
        "structural_quality_impact": {
          "value": "low",
          "reason": "The sequential structure is preserved. The only structural impact is the addition of one activity at the beginning of the process."
        },
        "change_location": {
          "value": "early",
          "reason": "The change is applied immediately before the first activity, 'Request personal data'."
        }
      }
    },
    {
      "resolution_strategy_id": "RS2_repurpose_existing_permission_activity",
      "change_operations": [
        {
          "operation": "rename",
          "parameters": {
            "target_activity_label": "Ask for permission",
            "new_activity_label": "obtain data processing consent"
          }
        },
        {
          "operation": "move_before",
          "parameters": {
            "source_activity_label": "obtain data processing consent",
            "target_activity_label": "Request personal data"
          }
        },
        {
          "operation": "modify_resource",
          "parameters": {
            "target_activity_label": "obtain data processing consent",
            "new_resource": "data controller"
          }
        }
      ],
      "evaluation": {
        "compliance_degree": {
          "value": "full",
          "reason": "The existing 'Ask for permission' activity is transformed into the required consent activity, moved before 'Request personal data', and assigned to the required resource."
        },
        "resolution_context_consistency": {
          "value": "medium",
          "reason": "Although no explicit context requirements are violated, moving 'Ask for permission' out of its original position after 'Store Data' may change the intended meaning of that part of the process."
        },
        "change_cost": {
          "value": "medium",
          "reason": "The strategy requires three operations and relocates an existing activity from a parallel branch to the beginning of the process."
        },
        "structural_quality_impact": {
          "value": "medium",
          "reason": "The strategy modifies the structure of the parallel section by removing an activity from one branch and relocating it to the early sequential part of the process."
        },
        "change_location": {
          "value": "early",
          "reason": "The final compliant consent activity is placed before 'Request personal data', which is at the beginning of the process."
        }
      }
    },
    {
      "resolution_strategy_id": "RS3_insert_consent_without_resource_assignment",
      "change_operations": [
        {
          "operation": "insert_before",
          "parameters": {
            "target_activity_label": "Request personal data",
            "new_activity_label": "obtain data processing consent"
          }
        }
      ],
      "evaluation": {
        "compliance_degree": {
          "value": "substantial",
          "reason": "The required activity is created and placed before 'Request personal data', satisfying the existence and precedence aspects of the requirement. However, the required execution by 'data controller' is not guaranteed."
        },
        "resolution_context_consistency": {
          "value": "high",
          "reason": "The change is limited to adding a single activity and does not affect any existing branches, activities, or ordering constraints."
        },
        "change_cost": {
          "value": "very_low",
          "reason": "Only one insertion operation is required."
        },
        "structural_quality_impact": {
          "value": "low",
          "reason": "The process remains a simple sequence at the beginning, with one added activity."
        },
        "change_location": {
          "value": "early",
          "reason": "The activity is inserted immediately before the first process activity."
        }
      }
    }
  ],
  "best_resolution_strategy_id": "RS1_insert_consent_before_personal_data",
  "best_resolution_reason": "RS1 is the best strategy because it fully restores compliance with minimal and localized changes. It adds the missing consent activity exactly where required and assigns it to the required resource without disturbing the existing process structure or moving existing activities."
}
